// Build list of 34 product chunk URLs
const base = 'https://raw.githubusercontent.com/Jean-Christophe972/mirakl-scraper/main/data/output/sql_chunks';
const urls = [];
for (let i = 1; i <= 34; i++) {
  const num = String(i).padStart(2, '0');
  urls.push({ chunk_num: i, url: `${base}/02_products_part_${num}.sql` });
}
return urls.map(u => ({ json: u }));
